mapper.select:
SELECT c.record_id AS ecgId, c.ecg_no AS ecgNo, c.collection_start_time AS collectTime, CONCAT( COALESCE(c.patient_name, ''), ' / ', COALESCE(c.gender, '未知'), ' / ', COALESCE(c.age, 0), '岁' ) AS patientInfo, c.patient_name AS patientName, c.inpatient_no AS inpatientNo, COALESCE(c.dept_name, '未知病区') AS ward, COALESCE(NULLIF(d.device_code, ''), NULLIF(c.device_name, ''), '-') AS deviceNo, CASE c.display_status WHEN 0 THEN '待分析' WHEN 1 THEN '已分析' WHEN 2 THEN '已审核' WHEN 3 THEN '已驳回' WHEN 4 THEN '采集失败' ELSE '未知' END AS status, COALESCE(NULLIF(c.ai_conclusion_short, ''), NULLIF(a.ai_conclusion, ''), '-') AS aiConclusion FROM ecg_collection_record c LEFT JOIN ecg_ai_diagnosis a ON a.record_id = c.record_id AND a.is_deleted = 0 LEFT JOIN ecg_device d ON d.device_id = c.device_id AND d.is_deleted = 0 WHERE c.is_deleted = 0
AND ( c.patient_name LIKE CONCAT('%', #{req.keyword}, '%') OR c.inpatient_no LIKE CONCAT('%', #{req.keyword}, '%') OR c.device_name LIKE CONCAT('%', #{req.keyword}, '%') OR d.device_code LIKE CONCAT('%', #{req.keyword}, '%') OR c.ecg_no LIKE CONCAT('%', #{req.keyword}, '%') )
AND c.dept_id = #{req.wardId}
AND c.display_status = #{statusCode}
AND c.collection_start_time >= #{startTime}
AND c.collection_start_time < #{endTime}
ORDER BY c.collection_start_time DESC, c.record_id DESC
